# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs). Prevent directory traversal attacks.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Net.Mime;

namespace FileServer.Controllers
{
    [Route("uploads/{filename}")]
    public class FileController : ControllerBase
    {
        private readonly string _uploadsFolder;

        public FileController(string uploadsFolder)
        {
            _uploadsFolder = uploadsFolder;
        }

        [HttpGet]
        public IActionResult GetFile(string filename)
        {
            string filePath = Path.Combine(_uploadsFolder, filename);

            if (!Path.IsPathRooted(filePath) || !filePath.StartsWith(_uploadsFolder))
            {
                return BadRequest("Invalid filename");
            }

            if (!System.IO.File.Exists(filePath))
            {
                return NotFound();
            }

            string contentType = MimeMapping.GetMimeMapping(Path.GetExtension(filePath));

            return File(System.IO.File.ReadAllBytes(filePath), contentType, filename);
        }
    }
}